function solve(n: number, m: number, k: number): number {
    if (k === 0) {
        return n * m; // Each cell needs its own sensor
    }

    // The maximum number of sensors needed in any case
    const max_sensors = Math.ceil(n / 2) * Math.ceil(m / 2);

    // If k is larger than or equal to the maximum possible distance
    if (k >= Math.floor(Math.min(n, m) / 2)) {
        return 1; // One sensor can cover the entire grid
    }

    // If k is larger than or equal to the maximum possible distance in one dimension
    if (k >= Math.floor(n / 2) || k >= Math.floor(m / 2)) {
        return max_sensors;
    }

    // Otherwise, use the maximum number of sensors
    return max_sensors;
}
